026-02-16T14:38:37.889000","updated_by":"","deleted_at":"","deleted_by":""},{"legacy_master_product_id":"696790229ac29d20ede481ad","legacy_org_id":"69864e74fb6fe137d3577c07","name":"KA 3C","description":"","notes":"","created_at":"2026-01-14T12:46:26.009000","created_by":"marquesmd9@gmail.com","updated_at":"2026-02-16T14:38:37.938000","updated_by":"","deleted_at":"","deleted_by":""},{"legacy_master_product_id":"69677f9362f1e0302a8cabf5","legacy_org_id":"69864ce67137a313e5c26d4d","name":"MOTOR 1.6 VOYAGE","description":"","notes":"","created_at":"2026-01-14T11:35:47.886000","created_by":"contato@loker.com.br","updated_at":"2026-02-16T14:38:50.156000","updated_by":"","deleted_at":"","deleted_by":""}]$master_products$::jsonb) AS src(
    legacy_master_product_id text,
    legacy_org_id text,
    name varchar(200),
    description text,
    notes text,
    created_at text,
    created_by varchar(200),
    updated_at text,
    updated_by varchar(200),
    deleted_at text,
    deleted_by varchar(200)
  );

  INSERT INTO public.master_products (
    id,
    organization_id,
    name,
    description,
    notes,
    created_at,
    created_by,
    updated_at,
    updated_by,
    deleted_at,
    deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'master_product:' || src.legacy_master_product_id),
    organizations.id,
    src.name,
    NULLIF(src.description, ''),
    NULLIF(src.notes, ''),
    COALESCE(NULLIF(src.created_at, '')::timestamptz, now()),
    NULLIF(src.created_by, ''),
    COALESCE(NULLIF(src.updated_at, '')::timestamptz, NULLIF(src.created_at, '')::timestamptz, now()),
    COALESCE(NULLIF(src.updated_by, ''), NULLIF(src.created_by, '')),
    NULLIF(src.deleted_at, '')::timestamptz,
    NULLIF(src.deleted_by, '')
  FROM tmp_master_product_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  WHERE src.legacy_org_id IS NOT NULL
    AND src.legacy_org_id <> ''
    AND src.name IS NOT NULL
    AND src.name <> ''
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = EXCLUDED.deleted_at,
    deleted_by = EXCLUDED.deleted_by;

  RAISE NOTICE 'Skipped % master products without resolvable organization or name.', (
    SELECT count(*)
    FROM tmp_master_product_source AS src
    LEFT JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id IS NULL
       OR src.legacy_org_id = ''
       OR src.name IS NULL
       OR src.name = ''
       OR organizations.id IS NULL
  );
END $$;
